/**
 * Emission evidence ledger — CASR substrate, no adjudicator.
 *
 * This is the low-churn alternative to committing every generated byte and
 * proving drift with `git diff --exit-code`. Instead of storing N generated
 * files, we store a content-addressed evidence stream that binds each emission's
 * DECLARED INPUTS to its PRODUCED OUTPUT, deduplicated by content hash:
 *
 *   observation_ref     = sha256(canonicalized declared inputs)   — "what governed this"
 *   attachment_ref      = sha256(emitted artifact bytes)          — "what it emitted"
 *   edge (obs -> attach) = the determinism claim                  — "these inputs yield these bytes"
 *
 * Because the FSDS generators are pure functions of their declared inputs
 * (proven: two independent wipe->generate runs are byte-identical), the edge
 * set is stable. Re-emitting an unchanged artifact produces an edge that already
 * exists in the committed stream, so it appends nothing — the churn collapses
 * from O(files-regenerated) to O(edges-that-actually-changed).
 *
 * DELIBERATELY NOT HERE: any trust/taint/allowed-use adjudication (CASR's
 * front-matter-governance machinery). Generated artifacts have no trust problem
 * — provenance is known a priori (the contract governs the artifact). Every row
 * is implicitly TRUSTED_GOVERNED_CONFIG. Adjudication only becomes load-bearing
 * if this ledger is later hooked into CI as a *gate that infers governance*;
 * for the substrate prototype it is out of scope.
 *
 * This module is target-agnostic: it knows nothing about icons or components.
 * Callers supply declared-input file paths and produced-output file paths; the
 * ledger computes hashes, builds rows, dedups, and serializes deterministically.
 */
import { createHash } from "node:crypto";
import fs from "node:fs";
import path from "node:path";

export const LEDGER_SCHEMA_VERSION = "emission_evidence_ledger.v1";
export const ROW_SCHEMA_VERSION = "emission_evidence_row.v1";
export const JOIN_SCHEMA_VERSION = "emission_evidence_join.v1";

/** sha256 of a UTF-8 string or Buffer, returned as `sha256:<hex>`. */
export function sha256(data) {
  return "sha256:" + createHash("sha256").update(data).digest("hex");
}

/** sha256 of a file's bytes. Throws if the file is unreadable — a missing
 * declared input is a load-bearing error, not a silently-skipped one. */
export function hashFile(absPath) {
  return sha256(fs.readFileSync(absPath));
}

/**
 * The input fingerprint (observation_ref): a hash over an ORDERED, LABELLED set
 * of declared-input files. Labelling each input by its logical role + a
 * repo-relative path (not absolute — absolute paths are machine-specific and
 * would break reproducibility across clones) makes the fingerprint stable and
 * auditable. Sorting by (role, relPath) guarantees order-independence of the
 * caller's input list.
 *
 * @param {Array<{role: string, relPath: string, absPath: string}>} inputs
 * @returns {{ ref: string, members: Array<{role: string, relPath: string, hash: string}> }}
 */
export function computeObservation(inputs) {
  const members = inputs
    .map((i) => ({ role: i.role, relPath: toPosix(i.relPath), hash: hashFile(i.absPath) }))
    .sort((a, b) => (a.role + " " + a.relPath).localeCompare(b.role + " " + b.relPath));
  // Canonical fingerprint text: role|relPath|hash per line, newline-joined.
  const canonical = members.map((m) => `${m.role}|${m.relPath}|${m.hash}`).join("\n");
  return { ref: sha256(canonical), members };
}

/**
 * Hash produced outputs into attachment refs, one per emitted file. Repo-relative
 * paths only. Returns entries sorted by relPath for a stable, diffable ordering.
 *
 * @param {Array<{relPath: string, absPath: string}>} outputs
 * @returns {Array<{relPath: string, ref: string, bytes: number}>}
 */
export function computeAttachments(outputs) {
  return outputs
    .map((o) => {
      const buf = fs.readFileSync(o.absPath);
      return { relPath: toPosix(o.relPath), ref: sha256(buf), bytes: buf.length };
    })
    .sort((a, b) => a.relPath.localeCompare(b.relPath));
}

/**
 * Build one evidence row binding a single emission unit's observation to the set
 * of attachments it produced. An "emission unit" is the smallest thing a caller
 * re-attests atomically — for icons, one icon contract; for components, one
 * (component, target) pair.
 *
 * @param {object} p
 * @param {string} p.unitId            stable id of the emission unit (e.g. "placeholder" or "Button@react")
 * @param {string} p.target            target family (e.g. "iconography" or "react")
 * @param {{ref: string, members: Array}} p.observation  from computeObservation
 * @param {Array<{relPath, ref, bytes}>} p.attachments   from computeAttachments
 */
export function buildRow({ unitId, target, observation, attachments }) {
  return {
    schema_version: ROW_SCHEMA_VERSION,
    unit_id: unitId,
    target,
    observation_ref: observation.ref,
    observation_members: observation.members,
    attachment_refs: attachments.map((a) => a.ref),
    attachments,
    admission_state: "emitted",
    // No taint/allowed-use fields: substrate-only, provenance known a priori.
    // No relation_verdict: the edge IS the relation; determinism, not inference.
  };
}

/**
 * Assemble the full ledger from rows, deriving the deduplicated join stream.
 *
 * The join stream is the load-bearing artifact: the SET of distinct
 * (observation_ref, attachment_ref) edges across all rows. Two targets that emit
 * a byte-identical file, or an unchanged unit re-attested, collapse to the same
 * edge — this is where the churn savings live. Rows are the per-unit detail;
 * joins are the drift oracle a gate checks against.
 *
 * Everything is sorted so the serialized ledger is a deterministic function of
 * its row set — a no-op regeneration produces a byte-identical ledger.
 */
export function assembleLedger(rows) {
  const sortedRows = rows
    .slice()
    .sort((a, b) => (a.target + " " + a.unit_id).localeCompare(b.target + " " + b.unit_id));

  const edgeSet = new Map(); // key -> {observation_ref, attachment_ref, rel_path}
  for (const row of sortedRows) {
    for (const att of row.attachments) {
      const key = row.observation_ref + " " + att.ref;
      if (!edgeSet.has(key)) {
        edgeSet.set(key, {
          schema_version: JOIN_SCHEMA_VERSION,
          observation_ref: row.observation_ref,
          attachment_ref: att.ref,
          rel_path: att.relPath,
        });
      }
    }
  }
  const joins = [...edgeSet.values()].sort((a, b) =>
    (a.observation_ref + a.attachment_ref).localeCompare(b.observation_ref + b.attachment_ref),
  );

  return {
    schema_version: LEDGER_SCHEMA_VERSION,
    row_count: sortedRows.length,
    edge_count: joins.length,
    rows: sortedRows,
    joins,
  };
}

/** Serialize a ledger to deterministic JSON (stable key order via construction). */
export function serializeLedger(ledger) {
  return JSON.stringify(ledger, null, 2) + "\n";
}

/**
 * Gate: assert every edge a fresh regeneration produced is present in the
 * committed ledger. Returns a verdict object; the CALLER decides exit code.
 *
 * `missing` = edges the fresh run produced that the committed ledger lacks
 * (un-attested emission — a real change not yet recorded, OR nondeterminism).
 * `stale` = edges the committed ledger has that the fresh run did NOT produce
 * (an artifact the generator no longer emits — e.g. the 5 orphan files the
 * component probe found). Both are reportable; `missing` is the hard failure.
 */
export function checkAgainstCommitted(freshLedger, committedLedger) {
  const freshEdges = new Set(freshLedger.joins.map(edgeKey));
  const committedEdges = new Set((committedLedger?.joins ?? []).map(edgeKey));

  const missing = freshLedger.joins.filter((e) => !committedEdges.has(edgeKey(e)));
  const stale = (committedLedger?.joins ?? []).filter((e) => !freshEdges.has(edgeKey(e)));

  return {
    ok: missing.length === 0,
    missing,
    stale,
    fresh_edge_count: freshEdges.size,
    committed_edge_count: committedEdges.size,
  };
}

function edgeKey(e) {
  return e.observation_ref + " " + e.attachment_ref;
}

function toPosix(p) {
  return p.split(path.sep).join("/");
}
